import { ParentApi } from "../constant/constant";

////////////////////////////////////////////////////////// AUTH //////////////////////////////////////////////////////////

export const ParentLoginApi = async (form_data) => {
    try {
        const { data } = await ParentApi.post('/login', form_data)
        return data;
    } catch (error) {
        return false
    }
}

//////////////////////////////////////////////////////////

export const ParentAuthApi = async (token) => {
    try {
        const { data } = await ParentApi.post('/auth', {}, { headers: { "parenttoken": token } })
        return data;
    } catch (error) {
        return false
    }
}

////////////////////////////////////////////////////////// ROOM //////////////////////////////////////////////////////////

export const ParentRoomList = async (token) => {
    try {
        const { data } = await ParentApi.get(`/room/list?hostel_i`, { headers: { "parenttoken": token } })
        return data;
    } catch (error) {
        return false
    }
}

////////////////////////////////////////////////////////// MENU //////////////////////////////////////////////////////////

export const ParentMenuList = async (token) => {
    try {
        const { data } = await ParentApi.get('/menu/list', { headers: { "parenttoken": token } })
        return data;
    } catch (error) {
        return false
    }
}

////////////////////////////////////////////////////////// COMPLAINT //////////////////////////////////////////////////////////

export const ParentComplaintList = async (token) => {
    try {
        const { data } = await ParentApi.get('/complaint/list', { headers: { "parenttoken": token } })
        return data;
    } catch (error) {
        return false
    }
}
